import React, { useState } from 'react';

const Tasks = () => {
  const [taskInput, setTaskInput] = useState('');
  const [tasks, setTasks] = useState([]);

  const addTask = () => {
    const trimmed = taskInput.trim();
    if (trimmed === '') return;

    const newTask = {
      id: Date.now(),
      title: trimmed,
      isEditing: false,
      items: [],
    };
    setTasks(prev => {
      const updated = [...prev, newTask];
      return updated.filter(task => task.title.trim() !== '');
    });
    setTaskInput('');
  };

  const removeEmptySubtask = (taskId, index) => {
  setTasks(prev =>
    prev.map(task =>
      task.id === taskId
        ? {
            ...task,
            items: task.items.filter((_, i) => i !== index || task.items[i].text.trim() !== ''),
          }
        : task
    )
  );
};

  const addItemToTask = (taskId) => {
    setTasks(prev =>
      prev.map(task =>
        task.id === taskId
          ? {
              ...task,
              items: [...task.items, { text: '', checked: false }],
            }
          : task
      )
    );
  };

  const toggleCheckbox = (taskId, index) => {
    setTasks(prev =>
      prev.map(task =>
        task.id === taskId
          ? {
              ...task,
              items: task.items.map((item, idx) =>
                idx === index ? { ...item, checked: !item.checked } : item
              ),
            }
          : task
      )
    );
  };

  const updateSubtaskText = (taskId, index, newText) => {
    setTasks(prev =>
      prev.map(task =>
        task.id === taskId
          ? {
              ...task,
              items: task.items.map((item, idx) =>
                idx === index ? { ...item, text: newText } : item
              ),
            }
          : task
      )
    );
  };

  const deleteTask = (taskId) => {
    setTasks(tasks.filter(task => task.id !== taskId));
  };

  const toggleEditTitle = (taskId) => {
    setTasks(prev =>
      prev.map(task =>
        task.id === taskId ? { ...task, isEditing: !task.isEditing } : task
      )
    );
  };

  const handleTitleChange = (taskId, newTitle) => {
    setTasks(prev =>
      prev.map(task =>
        task.id === taskId ? { ...task, title: newTitle } : task
      )
    );
  };

  return (
    <div className="task-page">
      <div className="task-input-row">
        <input
          type="text"
          value={taskInput}
          onChange={(e) => setTaskInput(e.target.value)}
          placeholder="Add Task ...."
          className="task-input"
        />
        <button onClick={addTask} className="add-btn">Add</button>
      </div>

      <div className="task-cards">
        {tasks.map(task => (
          <div key={task.id} className="task-card">
            <div className="task-header">
              {task.isEditing ? (
                <input
                  value={task.title}
                  onChange={(e) => handleTitleChange(task.id, e.target.value)}
                  onBlur={() => toggleEditTitle(task.id)}
                  autoFocus
                  className="task-title-input"
                />
              ) : (
                <span className="task-title">{task.title}</span>
              )}
              <div className="icons">
                <button onClick={() => addItemToTask(task.id)}>
                  <img className='icon' src='/assets/add.png' alt="Add" />
                </button>
                <button onClick={() => toggleEditTitle(task.id)}>
                  <img className='icon' src='/assets/edit.png' alt="Edit" />
                </button>
                <button onClick={() => deleteTask(task.id)}>
                  <img className='icon' src='/assets/delete.png' alt="Delete" />
                </button>
              </div>
            </div>

            <ul className="task-items">
              {task.items.map((item, index) => (
                <li key={index}>
                  <input
                    type="checkbox"
                    checked={item.checked}
                    onChange={() => toggleCheckbox(task.id, index)}
                  />
                  <input
                    className={`subtask-input ${item.checked ? 'checked' : ''}`}
                    type="text"
                    value={item.text}
                    onChange={(e) =>
                      updateSubtaskText(task.id, index, e.target.value)
                    }
                    onBlur={() => removeEmptySubtask(task.id, index)}
                    placeholder="Enter sub-task"
                  />
                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>
      <Stylesheet />
    </div>
  );
};

const Stylesheet = () => (
  <style>{`
    .task-page {
      padding: 2rem;
      font-family: 'Cedarville Cursive', cursive;
      
    }

    .task-input-row {
      display: flex;
      justify-content: center;
      gap: 1rem;
      margin-bottom: 2rem;
    }

    .task-input {
      background-color: var(--secondary-color);  
      border: none;
      padding: 1rem 1.5rem;
      font-size: 1.3rem;
      border-radius: 10px;
      width: 300px;
      font-family: 'Cedarville Cursive', cursive;
    }

    .add-btn {
      padding: 0.8rem 1.5rem;
      background-color: var(--button-color);
      color: var(--bg-parchment);
      border-radius: 10px;
      font-size: 1.2rem;
      cursor: pointer;
      border: none;
      font-family: 'Cedarville Cursive', cursive;
    }

    .task-cards {
      display: flex;
      justify-content: space-evenly;
      flex-wrap: wrap;
      gap: 2rem;
      margin-left:10%;
      margin-right:10%;
    }

    .task-card {
      background-color: var(--secondary-color);
      border: 2px solid var(--button-border);
      padding: 1rem;
      border-radius: 12px;
      width: 220px;
    }

    .task-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
    }

    .task-title {
      font-size: 1.2rem;
      font-weight: bold;
      color: var(--text);
    }

    .task-title-input {
      background-color: var(--flower-white);
      border: 1px solid var(--button-border);
      border-radius: 5px;
      font-size: 1rem;
      padding: 0.3rem;
      width: 80%;
      font-family: 'Cedarville Cursive', cursive;
    }

    .icons {
      display: flex;
    }

    .icons button {
      background: none;
      border: none;
      font-size: 1.1rem;
      margin-left: 5px;
      cursor: pointer;
    }

    .icon {
      height: 25px;
    }

    .task-items {
      margin-top: 1rem;
      list-style: none;
      padding: 0;
    }

    .task-items li {
      display: flex;
      align-items: center;
      gap: 0.5rem;
      margin: 0.3rem 0;
    }

    .subtask-input {
      flex: 1;
      background: transparent;
      border: none;
      font-size: 0.9rem;
      font-family: 'Cedarville Cursive', cursive;
    }

    .subtask-input:focus {
      outline: none;
    }

    .checked {
      text-decoration: line-through;
    }
  `}</style>
);

export default Tasks;
